### 10.5 src/debugger.rs (Detailed Overview)

This is the main 1452-line component. Key sections:

#### Constants & Enums
```rust
const BATCH_SIZE: u64 = 50_000;        // Instructions per tick
const TICK_MS: u32 = 25;               // Timer interval (milliseconds)
const DISASM_BEFORE: usize = 8;        // Lines before current PC
const DISASM_AFTER: usize = 16;        // Lines after current PC

// P-code opcode table (opcode → name mapping)
const PCODE_NAMES: &[(u8, &str)] = &[
    (0x00, "halt"),
    (0x01, "push"),
    (0x02, "push_s"),
    // ... 65+ opcodes
];

// vm_state struct field offsets (each field is 3 bytes = 1 word)
mod vm_offsets {
    pub const PC: u32 = 0;
    pub const ESP: u32 = 3;
    pub const CSP: u32 = 6;
    pub const FP_VM: u32 = 9;
    pub const GP: u32 = 12;
    pub const HP: u32 = 15;
    pub const CODE: u32 = 18;
    pub const STATUS: u32 = 21;
    pub const TRAP_CODE: u32 = 24;
}

// Decoded p-code instruction
struct PcodeInstr {
    addr: u32,
    name: &'static str,
    operand: Option<u32>,
    size: u32,
}

// Memory region selectable in hex viewer
